def parse_text(text):
    assignments = {}
    current_assignment = None
    
    # Split by Assignment headings
    parts = re.split(r'(Assignment \d+ \(Week \d+\))', text)
    
    for i in range(1, len(parts), 2):
        header = parts[i]
        content = parts[i+1]
        
        assign_num = int(re.search(r'Assignment (\d+)', header).group(1))
        
        # Split by QX.
        q_blocks = re.split(r'Q\d+\.', content)
        questions = []
        
        for block in q_blocks[1:]:
            block = block.strip()
            if not block: continue
            
            # Extract Correct Ans
            ans_match = re.search(r'Correct Ans:\s*([A-E])\.', block)
            if not ans_match: continue
            ans_letter = ans_match.group(1)
            ans_idx = ord(ans_letter) - ord('A')
            
            # Clean block: remove the Correct Ans part
            clean_block = re.split(r'Correct Ans:', block)[0].strip()
            
            # Extract options A. B. C. D. E.
            opts_parts = re.split(r'\s*([A-E])\.', clean_block)
            q_text = opts_parts[0].strip()
            
            opts = []
            for j in range(1, len(opts_parts), 2):
                opts.append(opts_parts[j+1].strip())
            
            questions.append({
                "q": q_text,
                "opts": opts,
                "a": ans_idx
            })
        
        assignments[assign_num] = {
            "title": header,
            "questions": questions
        }
    return assignments

parsed = parse_text(text)
print(json.dumps(parsed, indent=2))
